// Prefira esperar o estado da tela:
cy.get('.loading').should('not.exist');
cy.get('.conteudo').should('be.visible');

cy.intercept('POST', '/api/login').as('postLogin');
cy.get('form').submit();
cy.wait('@postLogin'); // espera a requisição POST completar
cy.get('.painel').should('be.visible');

