/**
 * Arquivo sugerido: cypress/e2e/trilha.cy.js
 * Kitchen Sink (demos oficiais):
 * - https://example.cypress.io/commands/actions
 * - https://example.cypress.io/commands/storage
 */

describe('Trilha de estudos — exemplos do curso', () => {
  it('Kitchen Sink: actions + storage', () => {
    cy.visit('https://example.cypress.io/commands/actions')

    // cy.get + .type (campo tipo email) + validação do valor
    cy.get('.action-email').clear().type('aluno@trilha.com')
    cy.get('.action-email').should('have.value', 'aluno@trilha.com')

    // Condicional if / else em cima do elemento retornado
    cy.get('.action-email').then(($el) => {
      if ($el.attr('type') === 'email') {
        cy.wrap($el).should('have.value', 'aluno@trilha.com')
      } else {
        cy.wrap($el).should('be.visible')
      }
    })

    // Outro .type: textarea com opção delay (teclas mais lentas, só para treino)
    cy.get('.action-clear').clear().type('Texto da trilha - passo 8', { delay: 30 })
    cy.get('.action-clear').should('have.value', 'Texto da trilha - passo 8')

    // Formulário: preencher + cy.submit + validar mensagem
    cy.get('.action-form').find('[type="text"]').clear().type('TRILHAOK')
    cy.get('.action-form').submit()
    cy.get('.action-form').next().should('contain', 'Your form has been submitted!')

    // Array + laço forEach: marcar duas opções (check) e validar
    const checks = ['checkbox1', 'checkbox3']
    checks.forEach((valor) => {
      cy.get(`.action-checkboxes [type="checkbox"][value="${valor}"]`).check()
    })
    checks.forEach((valor) => {
      cy.get(`.action-checkboxes [type="checkbox"][value="${valor}"]`).should('be.checked')
    })

    // .select: escolher 'oranges' e validar o value do <select> (Kitchen Sink)
    cy.get('.action-select').select('oranges')
    cy.get('.action-select').should('have.value', 'fr-oranges')

    // Cliques no canvas em posições diferentes (Kitchen Sink)
    cy.get('#action-canvas').click('topLeft')
    cy.get('#action-canvas').click('top')

    // localStorage (página dedicada — limpar, popular via botão, validar)
    cy.visit('https://example.cypress.io/commands/storage')
    cy.clearLocalStorage()
    cy.get('.ls-btn').click()
    cy.window().then((win) => {
      expect(win.localStorage.getItem('prop1')).to.eq('red')
      expect(win.localStorage.getItem('prop2')).to.eq('blue')
    })
  })
})

